func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// If redirectPath is empty, use the default from OAuthConfig
	if redirectPath == "" {
		redirectPath = OAuthConfig.RedirectURL
	}

	// Validate that redirectPath is a safe redirect URL
	if err := validateRedirectURL(redirectPath); err != nil {
		return "", fmt.Errorf("invalid redirect URL: %w", err)
	}

	// Generate a secure random state parameter
	state, err := generateState()
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

// validateRedirectURL ensures the redirect URL is safe to use
func validateRedirectURL(redirectURL string) error {
	if redirectURL == "" {
		return fmt.Errorf("redirect URL cannot be empty")
	}

	parsedURL, err := url.Parse(redirectURL)
	if err != nil {
		return fmt.Errorf("invalid URL format: %w", err)
	}

	// Ensure the URL has a scheme and is HTTPS (for security)
	if parsedURL.Scheme != "https" {
		return fmt.Errorf("redirect URL must use HTTPS")
	}

	// Ensure the URL is not a relative path
	if parsedURL.Host == "" {
		return fmt.Errorf("redirect URL must be absolute")
	}

	// Additional validation could be added here to restrict allowed domains
	// For example, only allow redirects to your own domain(s)
	allowedHosts := []string{"yourapp.com"} // Add your allowed hosts here
	isAllowed := false
	for _, allowedHost := range allowedHosts {
		if parsedURL.Host == allowedHost {
			isAllowed = true
			break
		}
		// Check for subdomains
		if len(parsedURL.Host) > len(allowedHost) && 
			parsedURL.Host[len(parsedURL.Host)-len(allowedHost):] == "."+allowedHost {
			isAllowed = true
			break
		}
	}
	if !isAllowed {
		return fmt.Errorf("redirect URL host is not allowed")
	}

	return nil
}

// generateState creates a cryptographically secure random state string
