package main

import (
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"net/http"
	"net/url"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate that the redirectPath is a valid URL
	redirectURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", fmt.Errorf("invalid redirect URL: %w", err)
	}

	// Ensure the redirect URL uses HTTPS (or HTTP for localhost during development)
	if redirectURL.Scheme != "https" {
		// Allow HTTP only for localhost (common in development)
		host := redirectURL.Hostname()
		if !(redirectURL.Scheme == "http" && (host == "localhost" || host == "127.0.0.1" || 
			host == "::1")) {
			return "", fmt.Errorf("redirect URL must use HTTPS")
		}
	}

	// Ensure the redirect URL is from an allowed domain
	// For this example, we'll check if it matches the base domain of the configured RedirectURL
	baseRedirectURL, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", fmt.Errorf("invalid base redirect URL configuration: %w", err)
	}

	// Check if the redirect URL's host matches the allowed domain or is a subdomain
	// This is a basic check - in production, you might want a more sophisticated allowlist
	if redirectURL.Host != baseRedirectURL.Host && !isSubdomain(redirectURL.Hostname(), baseRedirectURL.Hostname()) {
		return "", fmt.Errorf("redirect URL host not allowed")
	}

	// Generate a secure random state parameter
	state, err := generateState()
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	secureCookie := true
	if redirectURL.Scheme == "http" {
		secureCookie = false
	}

	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   secureCookie, // Should be false in development with HTTP
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

// generateState generates a cryptographically secure random state string
func generateState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return hex.EncodeToString(b), nil
}

// isSubdomain checks if subdomainHost is a subdomain of domainHost
func isSubdomain(subdomainHost, domainHost string) bool {
	if len(subdomainHost) <= len(domainHost) {
		return false
	}
	// Check if subdomainHost ends with "." + domainHost
	domainSuffix := "." + domainHost
	return len(subdomainHost) > len(domainSuffix) && subdomainHost[len(subdomainHost)-len(domainSuffix):] == domainSuffix
}

