)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate that the redirectPath is a valid URL and matches allowed domains/patterns
	if redirectPath == "" {
		redirectPath = OAuthConfig.RedirectURL
	}

	// Parse the redirect URL to validate it
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", fmt.Errorf("invalid redirect URL: %w", err)
	}

	// Security: Ensure the redirect URL uses HTTPS (except for localhost which can use HTTP for development)
	if parsedURL.Scheme != "https" {
		if !(parsedURL.Hostname() == "localhost" || parsedURL.Hostname() == "127.0.0.1" || parsedURL.Hostname() == "::1") {
			return "", fmt.Errorf("redirect URL must use HTTPS")
		}
	}

	// Security: Validate that the redirect URL is within allowed domains
	// For this example, we'll ensure it's under the same domain as the configured RedirectURL
	allowedBase, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", fmt.Errorf("invalid base redirect URL configuration: %w", err)
	}

	// Check if the redirectPath is on the same domain or a subdomain of the allowed base
	if !isAllowedRedirectDomain(parsedURL.Hostname(), allowedBase.Hostname()) {
		return "", fmt.Errorf("redirect URL domain not allowed")
	}

	// Generate a secure random state parameter
	state, err := generateRandomState()
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}

	// Create a copy of the OAuth config with the custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	// Only set Secure flag if the request is over HTTPS or if we're not on localhost
	secureFlag := parsedURL.Scheme == "https"
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   secureFlag,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

// generateRandomState generates a cryptographically secure random state string
func generateRandomState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return hex.EncodeToString(b), nil
}

// isAllowedRedirectDomain checks if the given hostname is allowed for redirects
// This is a basic implementation that allows the exact domain and subdomains
func isAllowedRedirectDomain(hostname, allowedDomain string) bool {
	if hostname == allowedDomain {
		return true
	}

	// Allow subdomains
	if len(hostname) > len(allowedDomain) && 
	   hostname[len(hostname)-len(allowedDomain)-1] == '.' && 
	   hostname[len(hostname)-len(allowedDomain):] == allowedDomain {
		return true
	}

	// Allow localhost for development
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" {
		return true
	}

	return false
}

